const currentYear=(new Date).getFullYear();const BREAKPOINTS={MOBILE:768,TOUCH_TIMEOUT:500,RESIZE_DEBOUNCE:150,LOGO_SCALE_DURATION:150};let resizeTimeout;document.addEventListener("DOMContentLoaded",()=>{const menuContainer=document.getElementById("menu-container");loadFooter();loadMenu(menuContainer)});async function loadFooter(){const footerPlaceholder=document.getElementById("footer-placeholder");if(!footerPlaceholder){console.warn("Footer-placeholder nicht gefunden - wird übersprungen");return}try{const response=await fetch("/pages/komponente/footer.html");if(!response.ok){throw new Error(`HTTP ${response.status}: Footer konnte nicht geladen werden`)}const html=await response.text();footerPlaceholder.innerHTML=html;const yearEl=document.getElementById("current-year");if(yearEl){yearEl.textContent=currentYear}}catch(err){console.error("Fehler beim Laden des Footers:",err.message);footerPlaceholder.innerHTML=createFallbackFooter()}}function createFallbackFooter(){return`\n    <footer class="site-footer footer" role="contentinfo">\n      <div class="footer-content">\n        <p>&copy; ${currentYear} Abdul Kerim. Alle Rechte vorbehalten.</p>\n      </div>\n    </footer>\n  `}async function loadMenu(menuContainer){if(!menuContainer){console.error("Fehler: menuContainer wurde nicht gefunden.");return}try{const response=await fetch("/pages/komponente/menu.html");if(!response.ok)throw new Error(`HTTP-Error! Status: ${response.status}`);const menuMarkup=await response.text();menuContainer.innerHTML=menuMarkup;initializeMenu(menuContainer);initializeLogo(menuContainer);initializeSubmenuLinks(menuContainer);initializeAccessibility(menuContainer);initializeThemeSwitcher();initializeSearch();setSiteTitle();setupOutsideClickHandler(menuContainer);setupResizeHandler(menuContainer)}catch(err){console.error("Fehler beim Laden des Menüs:",err.message);menuContainer.innerHTML=createFallbackMenu()}}function createFallbackMenu(){return`\n    <header class="site-header" role="banner">\n      <a href="/index.html" aria-label="Zur Startseite">\n        <span class="site-logo elegant-logo">Abdulkerim ⭐️</span>\n      </a>\n      <nav class="site-menu" role="navigation" aria-label="Hauptnavigation">\n        <ul class="site-menu-list">\n          <li><a href="/index.html"><i class="fa-solid fa-house" aria-hidden="true"></i>Startseite</a></li>\n          <li><a href="/pages/ubermich.html"><i class="fa-solid fa-user" aria-hidden="true"></i>Über mich</a></li>\n          <li><a href="/pages/album.html"><i class="fa-solid fa-images" aria-hidden="true"></i>Fotogalerie</a></li>\n        </ul>\n      </nav>\n    </header>\n  `}function initializeMenu(container){const menuToggle=container.querySelector(".site-menu-toggle");const menu=container.querySelector(".site-menu");const overlay=container.querySelector(".site-menu__overlay");if(!menuToggle||!menu){console.warn("Menu-Toggle-Elemente fehlen oder konnten nicht gefunden werden.");return}const toggleMenu=(isOpen=null)=>{const willBeOpen=isOpen!==null?isOpen:!menu.classList.contains("open");menu.classList.toggle("open",willBeOpen);menuToggle.classList.toggle("active",willBeOpen);menuToggle.setAttribute("aria-expanded",willBeOpen.toString());if(window.innerWidth<=BREAKPOINTS.MOBILE){document.body.style.overflow=willBeOpen?"hidden":""}};menuToggle.addEventListener("click",()=>toggleMenu());menuToggle.addEventListener("keydown",event=>{if(event.key==="Enter"||event.key===" "){event.preventDefault();toggleMenu()}if(event.key==="Escape"){toggleMenu(false)}});if(overlay){overlay.addEventListener("click",()=>toggleMenu(false))}}function initializeLogo(container){const logoContainer=container.querySelector(".site-logo__container");if(!logoContainer){console.warn("Logo-Container konnte nicht gefunden werden.");return}logoContainer.addEventListener("contextmenu",e=>{e.preventDefault();logoContainer.style.transform="scale(0.95)";setTimeout(()=>{logoContainer.style.transform="";window.location.href="/index.html"},BREAKPOINTS.LOGO_SCALE_DURATION)})}function initializeSubmenuLinks(container){const submenuLinks=container.querySelectorAll(".has-submenu > a");let touchStartTime=0;submenuLinks.forEach(link=>{link.addEventListener("touchstart",()=>{touchStartTime=Date.now()},{passive:true});link.addEventListener("click",event=>{const isMobile=window.innerWidth<=BREAKPOINTS.MOBILE;const isQuickTouch=Date.now()-touchStartTime<BREAKPOINTS.TOUCH_TIMEOUT;if(!isMobile&&!isQuickTouch)return;event.preventDefault();const parentLi=link.parentElement;const isOpen=parentLi.classList.contains("open");container.querySelectorAll(".has-submenu").forEach(li=>{if(li!==parentLi)li.classList.remove("open")});parentLi.classList.toggle("open",!isOpen);link.setAttribute("aria-expanded",(!isOpen).toString())});link.addEventListener("keydown",event=>{if(event.key==="ArrowDown"||event.key==="Enter"){event.preventDefault();const parentLi=link.parentElement;parentLi.classList.add("open");link.setAttribute("aria-expanded","true");const firstSubmenuLink=parentLi.querySelector(".submenu a");if(firstSubmenuLink)firstSubmenuLink.focus()}})})}function initializeAccessibility(container){document.addEventListener("keydown",event=>{if(event.key==="Escape"){container.querySelectorAll(".has-submenu").forEach(li=>{li.classList.remove("open");li.querySelector("a").setAttribute("aria-expanded","false")});closeMenu(container)}});const menuLinks=container.querySelectorAll("a");menuLinks.forEach((link,index)=>{link.addEventListener("keydown",event=>{if(event.key==="ArrowDown"){event.preventDefault();const nextLink=menuLinks[index+1];if(nextLink)nextLink.focus()}if(event.key==="ArrowUp"){event.preventDefault();const prevLink=menuLinks[index-1];if(prevLink)prevLink.focus()}})})}function closeMenu(container){const menuToggle=container.querySelector(".site-menu-toggle");const menu=container.querySelector(".site-menu");if(menuToggle&&menu){menu.classList.remove("open");menuToggle.classList.remove("active");menuToggle.setAttribute("aria-expanded","false");document.body.style.overflow="";container.querySelectorAll(".has-submenu").forEach(li=>{li.classList.remove("open");li.querySelector("a").setAttribute("aria-expanded","false")})}}function setupOutsideClickHandler(menuContainer){const handleOutsideClick=event=>{const menu=menuContainer.querySelector(".site-menu");if(!menu?.classList.contains("open"))return;const isClickInside=menuContainer.contains(event.target);const isMenuToggle=event.target.closest(".site-menu-toggle");if(!isClickInside&&!isMenuToggle){closeMenu(menuContainer)}};document.addEventListener("click",handleOutsideClick,{passive:true})}function setupResizeHandler(menuContainer){const handleResize=()=>{clearTimeout(resizeTimeout);resizeTimeout=setTimeout(()=>{if(window.innerWidth>BREAKPOINTS.MOBILE){closeMenu(menuContainer);document.body.style.overflow=""}},BREAKPOINTS.RESIZE_DEBOUNCE)};window.addEventListener("resize",handleResize,{passive:true})}function setSiteTitle(){const titleMap={"/index.html":"Startseite","/":"Startseite","/pages/album.html":"Fotogalerie","/pages/ubermich.html":"Über mich","/pages/index-game.html":"Spiele-Übersicht","/pages/features/wetter.html":"Wetter","/pages/features/snake.html":"Snake Spiel","/pages/features/tetris.html":"Tetris Spiel","/pages/features/Run.html":"Jump & Run","/pages/features/editor.html":"Level Editor","/pages/komponente/kontakt.html":"Kontakt","/pages/komponente/impressum.html":"Impressum","/pages/komponente/datenschutz.html":"Datenschutz"};const path=window.location.pathname;const pageTitle=titleMap[path]||document.title||"Abdul Kerim";const siteTitleEl=document.getElementById("site-title");if(siteTitleEl){siteTitleEl.textContent=pageTitle;siteTitleEl.setAttribute("aria-label",`Aktuelle Seite: ${pageTitle}`)}}function initializeThemeSwitcher(){const themeToggles=document.querySelectorAll(".theme-toggle-checkbox");if(themeToggles.length===0)return;const currentTheme=localStorage.getItem("theme")||"dark";document.documentElement.setAttribute("data-theme",currentTheme);themeToggles.forEach(toggle=>{toggle.checked=currentTheme==="dark"});updateThemeIcons(currentTheme);document.body.addEventListener("change",e=>{if(e.target.classList.contains("theme-toggle-checkbox")){const newTheme=e.target.checked?"dark":"light";document.documentElement.setAttribute("data-theme",newTheme);localStorage.setItem("theme",newTheme);themeToggles.forEach(t=>{if(t!==e.target){t.checked=e.target.checked}});updateThemeIcons(newTheme)}})}function updateThemeIcons(theme){const themeIcons=document.querySelectorAll(".theme-icon");themeIcons.forEach(icon=>{if(theme==="dark"){icon.className="theme-icon fa-solid fa-sun"}else{icon.className="theme-icon fa-solid fa-moon"}})}function initializeSearch(){const searchContainers=document.querySelectorAll(".search-container");if(searchContainers.length===0)return;searchContainers.forEach(container=>{const toggle=container.querySelector(".search-toggle");const input=container.querySelector(".search-input");if(!toggle||!input)return;if(!container.parentElement.classList.contains("mobile-actions")){toggle.addEventListener("click",e=>{e.stopPropagation();const isActive=container.classList.toggle("active");toggle.setAttribute("aria-expanded",isActive);if(isActive){input.focus()}})}input.addEventListener("keydown",e=>{if(e.key==="Enter"){alert(`Searching for: ${input.value}`)}})});document.addEventListener("click",e=>{searchContainers.forEach(container=>{if(!container.parentElement.classList.contains("mobile-actions")&&!container.contains(e.target)){container.classList.remove("active");container.querySelector(".search-toggle").setAttribute("aria-expanded","false")}})})}